// ============================================================
// NODE: Input Cleaner & Language Detector
// ============================================================
const body = $input.first().json.body || $input.first().json;
const rawQuestion = (body.message || body.question || '').trim();

if (!rawQuestion) {
  throw new Error('Missing "question" field in request body.');
}

if (rawQuestion.length > 1000) {
  throw new Error('Question too long. Maximum 1000 characters.');
}

// Detect language
const arabicPattern = /[\u0600-\u06FF\u0750-\u077F\u08A0-\u08FF]/;
const isArabic = arabicPattern.test(rawQuestion);
const detectedLang = isArabic ? 'ar' : 'en';

// Clean the question: strip HTML tags, normalize whitespace
const cleanQuestion = rawQuestion
  .replace(/<[^>]+>/g, '')
  .replace(/[<>"';]/g, '')
  .replace(/\s+/g, ' ')
  .trim();

// Execution tracking
const startTime = Date.now();

return [{
  json: {
    originalQuestion: rawQuestion,
    cleanQuestion,
    detectedLang,
    isArabic,
    startTime,
    requestId: `NLQ-${Date.now()}-${Math.random().toString(36).substr(2, 6).toUpperCase()}`
  }
}];

// ============================================================
// NODE: SQL Validator & Sanitizer
// Cleans AI output, blocks dangerous SQL, enforces SELECT-only
// ============================================================
const rawSql =
  $input.first().json.message?.content ||
  $input.first().json.text ||
  $input.first().json.output ||
  '';

// --- Step 1: Strip markdown fences ---
let sql = rawSql
  .replace(/```sql\s*/gi, '')
  .replace(/```\s*/g, '')
  .replace(/^sql\s*/i, '')
  .trim();

// --- Step 2: Extract chart type hint from first line comment ---
const chartMatch = sql.match(/^--\s*chart:(\w+)/i);
const suggestedChart = chartMatch ? chartMatch[1].toLowerCase() : 'table';

// Remove the chart hint line from SQL for cleanliness
sql = sql.replace(/^--\s*chart:\w+\s*\n?/i, '').trim();

// --- Step 3: Block dangerous keywords (case-insensitive, word boundaries) ---
const BLOCKED = [
  'DELETE', 'DROP', 'UPDATE', 'INSERT', 'ALTER', 'TRUNCATE',
  'EXEC', 'EXECUTE', 'xp_', 'sp_', 'OPENROWSET', 'BULK INSERT',
  'SHUTDOWN', 'RESTORE', 'BACKUP', 'GRANT', 'REVOKE', 'DENY',
  'CREATE', 'INTO', 'MERGE', 'CALL'
];

const sqlUpper = sql.toUpperCase();
const blocked = BLOCKED.filter((kw) => {
  const pattern = new RegExp(`\\b${kw.replace('_', '\\s*')}\\b`, 'i');
  return pattern.test(sqlUpper);
});

if (blocked.length > 0) {
  return [{
    json: {
      valid: false,
      reason: `Blocked keywords detected: ${blocked.join(', ')}`,
      sql: null,
      suggestedChart: 'table',
    },
  }];
}

// --- Step 4: Must start with SELECT (after removing comments) ---
const sqlNoComments = sql.replace(/--[^\n]*/g, '').trim();
const firstToken = sqlNoComments.match(/^\S+/);
if (!firstToken || firstToken[0].toUpperCase() !== 'SELECT') {
  return [{
    json: {
      valid: false,
      reason: 'Query must begin with SELECT',
      sql: null,
      suggestedChart: 'table',
    },
  }];
}

// --- Step 5: Add TOP 100 if no TOP / no ROW_NUMBER pagination ---
if (!/\bTOP\s+\d+\b/i.test(sql) && !/ROW_NUMBER\s*\(/i.test(sql)) {
  sql = sql.replace(/^SELECT\s+/i, 'SELECT TOP 100 ');
}

// --- Step 6: Validate SQL length ---
if (sql.length > 5000) {
  return [{
    json: {
      valid: false,
      reason: 'Generated SQL exceeds maximum allowed length',
      sql: null,
      suggestedChart: 'table',
    },
  }];
}

// --- Step 7: Validate it references at least one known table ---
const KNOWN_TABLES = [
  'Fact_Trip', 'Fact_DriverEarnings', 'Fact_Complaint', 'Fact_Rating',
  'Dim_Date', 'Dim_Time', 'Dim_Zone', 'Dim_Rider', 'Dim_Driver',
  'Dim_Payment', 'Dim_Promotion', 'Dim_SeasonalPattern', 'Dim_SurgeRule',
];
const referencesKnownTable = KNOWN_TABLES.some((t) =>
  new RegExp(`\\b${t}\\b`, 'i').test(sql)
);

if (!referencesKnownTable) {
  return [{
    json: {
      valid: false,
      reason: 'Query does not reference any known Ridelytics DWH table',
      sql: null,
      suggestedChart: 'table',
    },
  }];
}

return [{
  json: {
    valid: true,
    reason: 'OK',
    sql: sql.trim(),
    suggestedChart,
  },
}];

// ============================================================
// NODE: Result Formatter
// Builds final response with chart type, data, and metadata
// ============================================================
const rows = $input.all().map(item => item.json);
const validatorData = $('SQL Validator').first().json;
const inputData = $('Input Cleaner').first().json;
const startTime = inputData.startTime;
const executionTimeMs = Date.now() - startTime;

// Determine column names from first row
const columns = rows.length > 0 ? Object.keys(rows[0]) : [];

// ---- Chart type refinement based on column patterns ----
let chartType = validatorData.suggestedChart || 'table';

if (rows.length === 1 && columns.length === 1) {
  chartType = 'kpi';
} else if (columns.some(c => /date|month|week|year|day/i.test(c)) && rows.length > 2) {
  chartType = 'line';
} else if (columns.some(c => /percent|ratio|share|proportion/i.test(c))) {
  chartType = 'pie';
} else if (columns.some(c => /zone|governorate|city|region/i.test(c))) {
  chartType = 'map';
} else if (rows.length <= 10 && chartType !== 'kpi') {
  chartType = 'bar';
}

// ---- Generate human-readable query explanation ----
const lang = inputData.detectedLang;
let explanation;
if (lang === 'ar') {
  explanation = `تم تنفيذ الاستعلام بنجاح. النتيجة تحتوي على ${rows.length} صف و${columns.length} عمود. وقت التنفيذ: ${executionTimeMs}ms.`;
} else {
  explanation = `Query executed successfully. Returned ${rows.length} row(s) across ${columns.length} column(s). Execution time: ${executionTimeMs}ms.`;
}

// ---- Log entry (would be saved to a log table in production) ----
const logEntry = {
  requestId: inputData.requestId,
  question: inputData.cleanQuestion,
  language: inputData.detectedLang,
  sql: validatorData.sql,
  rowCount: rows.length,
  executionTimeMs,
  chartType,
  timestamp: new Date().toISOString()
};

return [{
  json: {
    success: true,
    requestId: inputData.requestId,
    question: inputData.cleanQuestion,
    language: inputData.detectedLang,
    sql: validatorData.sql,
    chartType,
    columns,
    rowCount: rows.length,
    data: rows,
    explanation,
    executionTimeMs,
    log: logEntry
  }
}];

// ============================================================
// NODE: Error Response Builder
// Handles both validation failures and SQL execution errors
// ============================================================
const inputData = $('Input Cleaner').first().json;
const validatorData = $('SQL Validator').first().json;
const lang = inputData.detectedLang || 'en';

const errorReason = validatorData.reason || 'Unknown validation error';

let userMessage;
if (lang === 'ar') {
  const msgMap = {
    'Blocked keywords detected': 'عذراً، لا يمكن تنفيذ عمليات التعديل على قاعدة البيانات. يُسمح فقط بالاستعلام.',
    'Query must begin with SELECT': 'حدث خطأ في توليد الاستعلام. حاول إعادة صياغة سؤالك.',
    'Query does not reference': 'لم أتمكن من ربط سؤالك بجداول قاعدة بيانات Ridelytics. حاول أن تكون أكثر تحديداً.',
    'DEFAULT': 'حدث خطأ أثناء معالجة سؤالك. يرجى المحاولة مرة أخرى أو إعادة الصياغة.'
  };
  const key = Object.keys(msgMap).find(k => errorReason.includes(k)) || 'DEFAULT';
  userMessage = msgMap[key];
} else {
  userMessage = `Unable to process your query: ${errorReason}. Please rephrase your question.`;
}

return [{
  json: {
    success: false,
    requestId: inputData.requestId,
    question: inputData.cleanQuestion,
    language: lang,
    error: errorReason,
    userMessage,
    sql: null,
    data: [],
    chartType: null,
    timestamp: new Date().toISOString()
  }
}];
